import{_ as n,c as i,o as r,a1 as t}from"./chunks/framework.DILC4Csi.js";const c=JSON.parse('{"title":"Erweiterte Funktionen: Optimierung | opencode-supermemory","description":"Lernen Sie die tiefgehenden Mechanismen und Konfigurationsoptionen von Supermemory. Optimieren Sie die Speicher-Engine und passen Sie das Pluginverhalten an Ihre Projektanforderungen an.","frontmatter":{"title":"Erweiterte Funktionen: Optimierung | opencode-supermemory","sidebarTitle":"Erweiterte Funktionen","subtitle":"Erweiterte Funktionen: Optimierung","order":3,"description":"Lernen Sie die tiefgehenden Mechanismen und Konfigurationsoptionen von Supermemory. Optimieren Sie die Speicher-Engine und passen Sie das Pluginverhalten an Ihre Projektanforderungen an."},"headers":[],"relativePath":"de/supermemoryai/opencode-supermemory/advanced/index.md","filePath":"de/supermemoryai/opencode-supermemory/advanced/index.md"}'),a={name:"de/supermemoryai/opencode-supermemory/advanced/index.md"};function s(o,e,l,u,p,d){return r(),i("div",null,[...e[0]||(e[0]=[t(`<h1 id="erweiterte-funktionen" tabindex="-1">Erweiterte Funktionen <a class="header-anchor" href="#erweiterte-funktionen" aria-label="Permalink to &quot;Erweiterte Funktionen&quot;">​</a></h1><p>Dieses Kapitel erklärt tiefgehend die zugrundeliegenden Mechanismen und erweiterten Konfigurationsoptionen von Supermemory. Sie lernen, wie Sie die Leistung der Speicher-Engine optimieren und das Pluginverhalten nach Projektanforderungen anpassen.</p><h2 id="dieses-kapitel-enthalt" tabindex="-1">Dieses Kapitel enthält <a class="header-anchor" href="#dieses-kapitel-enthalt" aria-label="Permalink to &quot;Dieses Kapitel enthält&quot;">​</a></h2><div class="grid-cards"><h3 id="praemptive-komprimierungsprinzipien" tabindex="-1"><a href="./compaction/">Präemptive Komprimierungsprinzipien</a> <a class="header-anchor" href="#praemptive-komprimierungsprinzipien" aria-label="Permalink to &quot;[Präemptive Komprimierungsprinzipien](./compaction/)&quot;">​</a></h3><p>Verstehen Sie den durch Token-Schwellenwert ausgelösten automatischen Komprimierungsmechanismus. Lernen Sie, wie Supermemory vor dem Überlauf des Kontexts automatisch strukturierte Zusammenfassungen generiert und persistent speichert, um &quot;Vergesslichkeit&quot; in langen Sitzungen zu verhindern.</p><h3 id="tiefenkonfiguration-detaillierung" tabindex="-1"><a href="./configuration/">Tiefenkonfiguration-Detaillierung</a> <a class="header-anchor" href="#tiefenkonfiguration-detaillierung" aria-label="Permalink to &quot;[Tiefenkonfiguration-Detaillierung](./configuration/)&quot;">​</a></h3><p>Passen Sie Komprimierungsschwellenwerte, Schlüsselwortauslöseregeln und Suchparameter an. Meistern Sie alle Konfigurationsoptionen der Konfigurationsdatei, damit Supermemory perfekt an Ihren Workflow angepasst wird.</p></div><h2 id="lernpfad" tabindex="-1">Lernpfad <a class="header-anchor" href="#lernpfad" aria-label="Permalink to &quot;Lernpfad&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│  Schritt 1          Schritt 2                                │</span></span>
<span class="line"><span>│  Präemptive Komprimierungsprinzipien  →   Tiefenkonfiguration-Detaillierung  │</span></span>
<span class="line"><span>│  (Mechanismus verstehen)           (Anpassen)               │</span></span>
<span class="line"><span>└─────────────────────────────────────────────────────────────┘</span></span></code></pre></div><p><strong>Empfohlene Reihenfolge</strong>:</p><ol><li><strong>Lernen Sie zuerst Komprimierungsprinzipien</strong>: Verstehen Sie, wie Supermemory automatisch Kontext verwaltet. Dies ist die Grundlage für erweiterte Konfiguration.</li><li><strong>Lernen Sie dann Konfiguration-Detaillierung</strong>: Nachdem Sie den Mechanismus verstehen, können Sie vernünftige Konfigurationsentscheidungen treffen (z. B. welchen Schwellenwert Sie festlegen sollten).</li></ol><h2 id="voraussetzungen" tabindex="-1">Voraussetzungen <a class="header-anchor" href="#voraussetzungen" aria-label="Permalink to &quot;Voraussetzungen&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Bitte bestätigen Sie vor dem Start</p><p>Dieses Kapitel setzt voraus, dass Sie Folgendes abgeschlossen haben:</p><ul><li>✅ <a href="./../start/getting-started/">Schnellstart</a>: Plugin installiert und API Key konfiguriert</li><li>✅ <a href="./../core/memory-management/">Speicherumfang und Lebenszyklus</a>: Verstehen Sie den Unterschied zwischen User Scope und Project Scope</li></ul></div><h2 id="nachste-schritte" tabindex="-1">Nächste Schritte <a class="header-anchor" href="#nachste-schritte" aria-label="Permalink to &quot;Nächste Schritte&quot;">​</a></h2><p>Nach Abschluss dieses Kapitels empfehle ich, weiter zu lernen:</p><ul><li><strong><a href="./../security/privacy/">Privatsphäre und Datensicherheit</a></strong>: Erfahren Sie mehr über den Mechanismus zur Maskierung sensibler Daten, um sicherzustellen, dass Ihr Code und Ihre Schlüssel nicht versehentlich hochgeladen werden.</li></ul>`,13)])])}const m=n(a,[["render",s]]);export{c as __pageData,m as default};
